#include <iostream>
using namespace std;
long long fact(int a,int b){
	return b==0 ? a:fact(b,a%b);
}
int main(){
	long long n,a[11],sum;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	sum=a[1]*a[2]/fact(a[1],a[2]);
	for(int i=3;i<=n;i++)sum=sum*a[i]/fact(sum,a[i]);
	cout<<sum;
	return 0;
}
